SELECT ORDERH.REF AS order_id, ORDERH.QTRESULTORDERREF AS original_quote_id, ORDERH.UF_SHIPMENTREF AS shipment_id, ORDERH.UF_SHIPMENTNAME AS shipment_name, ORDERH.OHQTEXPIRYDATE AS expiry_date, ORDERH.OHSPLPRICEPOINT AS price_date, ORDERH.OHSPLTERMS AS quote_type_int, ORDERH.UF_VERSION AS version, ORDERH.UF_CSA AS csa_code, ORDERH.OHINVDATE AS invoice_date, ORDERH.OHINVREF AS invoice_id, ORDERH.UF_SHIPOUT AS shipment_date, ORDERH.NOTES AS special_instructions, ORDERH.TITLE AS order_reference, ORDERH.CRNOTE AS credit_note, ORDERH.CUSTCODE AS customer_code FROM ORDERH WHERE ORDERH.QTRESULTORDERREF IS NOT NULL WHERE ORDERH.INSTATUS = 1 AND (CAST(ORDERH.REF AS INTEGER) BETWEEN ? AND ?);
